import React, { useEffect, useMemo, useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";

const Home = () => {
  const navigate = useNavigate();

  const [vehicles, setVehicles] = useState([]);
  const [filteredVehicles, setFilteredVehicles] = useState([]);
  const [selectedType, setSelectedType] = useState("all");
  const [types, setTypes] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchVehicles = async () => {
      try {
        setLoading(true);
        const res = await axios.get("http://localhost:8070/api/vehicles");

        const available = (res.data || []).filter(
          (v) => (v.status || "").toLowerCase() === "available"
        );

        setVehicles(available);
        setFilteredVehicles(available);

        const uniqueTypes = [
          ...new Set(available.map((v) => v.type).filter(Boolean)),
        ];
        setTypes(uniqueTypes);
      } catch (err) {
        console.error("Error fetching vehicles", err);
      } finally {
        setLoading(false);
      }
    };

    fetchVehicles();
  }, []);

  const handleFilterChange = (e) => {
    const value = e.target.value;
    setSelectedType(value);

    if (value === "all") {
      setFilteredVehicles(vehicles);
    } else {
      setFilteredVehicles(vehicles.filter((v) => v.type === value));
    }
  };

  const stats = useMemo(() => {
    const total = vehicles.length;
    const totalValue = vehicles.reduce((sum, v) => sum + Number(v.price || 0), 0);
    const avgPrice = total ? totalValue / total : 0;

    return {
      total,
      types: types.length,
      totalValue,
      avgPrice,
    };
  }, [vehicles, types]);

  return (
    <div className="page">
      {/* Page Header */}
      <div className="pageHead">
        <div>
          <div className="pageTitle">Dashboard Overview</div>
          <div className="pageSub">Browse our available vehicles and inventory</div>
        </div>
      </div>

      {/* KPI Cards */}
      <div className="kpiGrid">
        <div className="kpiCard">
          <div className="kpiLabel">Available Vehicles</div>
          <div className="kpiValue">{loading ? "—" : stats.total}</div>
          <div className="kpiSub">Current live inventory</div>
        </div>

        <div className="kpiCard">
          <div className="kpiLabel">Vehicle Categories</div>
          <div className="kpiValue">{loading ? "—" : stats.types}</div>
          <div className="kpiSub">Distinct vehicle types</div>
        </div>

        <div className="kpiCard">
          <div className="kpiLabel">Inventory Value</div>
          <div className="kpiValue">
            {loading ? "—" : `LKR ${Number(stats.totalValue).toLocaleString()}`}
          </div>
          <div className="kpiSub">Combined available stock value</div>
        </div>

        <div className="kpiCard">
          <div className="kpiLabel">Average Price</div>
          <div className="kpiValue">
            {loading ? "—" : `LKR ${Math.round(stats.avgPrice).toLocaleString()}`}
          </div>
          <div className="kpiSub">Average market listing price</div>
        </div>
      </div>

      {/* Filter Card */}
      <div className="card cardPad" style={{ marginBottom: 14 }}>
        <div className="row" style={{ alignItems: "center", flexWrap: "wrap" }}>
          <div>
            <div className="sectionTitle">Vehicle Inventory</div>
            <div className="sub">Browse currently available vehicles</div>
          </div>

          <div style={{ display: "flex", gap: 10, alignItems: "center", flexWrap: "wrap" }}>
            <select
              className="select"
              value={selectedType}
              onChange={handleFilterChange}
              style={{ minWidth: 180 }}
            >
              <option value="all">All Types</option>
              {types.map((t) => (
                <option key={t} value={t}>
                  {t}
                </option>
              ))}
            </select>

            <div className="sub">
              Showing <b>{filteredVehicles.length}</b> vehicle(s)
            </div>
          </div>
        </div>
      </div>

      {/* Inventory Grid */}
      {loading ? (
        <div className="card cardPad" style={{ textAlign: "center", padding: "40px 20px" }}>
          <div className="muted">Loading inventory...</div>
        </div>
      ) : filteredVehicles.length === 0 ? (
        <div className="card cardPad" style={{ textAlign: "center", padding: "40px 20px" }}>
          <div className="muted">No vehicles found for the selected type.</div>
        </div>
      ) : (
        <div className="gridCards3">
          {filteredVehicles.map((v) => (
            <div key={v._id} className="card" style={{ cursor: "pointer" }}>
              <div className="cardPad" style={{ display: "grid", gap: 12 }}>
                <div className="row" style={{ alignItems: "flex-start" }}>
                  <div>
                    <div
                      style={{
                        fontWeight: 950,
                        fontSize: 17,
                        color: "var(--navy)",
                      }}
                    >
                      {v.brand}
                    </div>
                    <div className="sub" style={{ marginTop: 4 }}>
                      {v.type} • {v.year}
                    </div>
                  </div>

                  <span className="badge badgeOk">
                    {v.status || "available"}
                  </span>
                </div>

                <div className="hr" />

                <div style={{ display: "grid", gap: 8 }}>
                  <InfoRow
                    label="Price"
                    value={`LKR ${Number(v.price || 0).toLocaleString()}`}
                  />
                  <InfoRow
                    label="Vehicle No."
                    value={v.vehicleNumber || "-"}
                  />
                  <InfoRow
                    label="Details"
                    value={v.details || "-"}
                    clamp
                  />
                </div>

                <div style={{ marginTop: 6, display: "flex", gap: 10, flexWrap: "wrap" }}>
                  <button
                    className="btn btnPrimary"
                    onClick={() => navigate(`/vehicles/${v._id}`)}
                  >
                    View Details
                  </button>

                  <button
                    className="btn btnGreen"
                    onClick={() =>
                      navigate("/book-appointment", {
                        state: { vehicleId: v._id },
                      })
                    }
                  >
                    Book Now
                  </button>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

function InfoRow({ label, value, clamp }) {
  return (
    <div style={{ display: "flex", justifyContent: "space-between", gap: 14 }}>
      <div style={{ opacity: 0.65, fontWeight: 800, fontSize: "13px" }}>{label}</div>
      <div
        style={{
          fontWeight: 900,
          textAlign: "right",
          maxWidth: 220,
          overflow: "hidden",
          textOverflow: "ellipsis",
          whiteSpace: clamp ? "nowrap" : "normal",
          color: "var(--navy)",
          fontSize: "13px",
        }}
        title={typeof value === "string" ? value : ""}
      >
        {value}
      </div>
    </div>
  );
}

export default Home;
